  "decisions": [
    {
      "id": "D1",
      "content": "本日をもってプロジェクト・アオゾラを正式キックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10時から1時間枠で開催する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行は第1フェーズでマスタ系のみを対象とし、トランザクション系は移行せず旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "共通基盤はサクラ商事との共同利用で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "障害発生時の一次受け窓口はQAチームとする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "移行方式は拠点を分けて順番に切り替える段階移行とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "本番リリース目標は9月末を撤回し、2026-10-15に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "切替作業は土曜深夜帯を前提として進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "新システムのユーザー権限は既存のロール定義を流用し、新規設計は行わない。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D10",
      "content": "開発ベンダー候補としてハギワラ技研は納期面、ツヅキシステムは金額面で見送りとする。",
      "decided_by": "郡司 明久"
    }
  ],
